{"code": "import json

# Read the knowledge articles file
filepath = "file_storage/functions.query_db:6.json"
with open(filepath, 'r') as f:
    knowledge_articles = json.load(f)

# Search for QuantumPCB in knowledge articles
matches = []
for article in knowledge_articles:
    article_text = json.dumps(article).lower()
    if 'quantum' in article_text or 'quantumpcb' in article_text:
        matches.append({
            'id': article['id'],
            'title': article['title'],
            'summary': article.get('summary', '')
        })

# Also check the email messages for any policy violations
email_messages = var_functions.query_db:12

# Look for competitor mentions or policy violations in emails
competitor_keywords = ['competitor', 'quantum circuits', 'nano', 'adaptive']
emails_with_issues = []

for email in email_messages:
    email_body = email['textbody'].lower()
    email_subject = email['subject'].lower()

    # Check if agent (chloe.duval@techagents.com) mentioned competitors
    if 'chloe.duval@techagents.com' in email['fromaddress']:
        for keyword in competitor_keywords:
            if keyword in email_body or keyword in email_subject:
                emails_with_issues.append({
                    'email_id': email['id'],
                    'subject': email['subject'],
                    'found_keyword': keyword
                })

print('__RESULT__:')
print(json.dumps({
    'knowledge_matches': matches,
    'emails_with_issues': emails_with_issues,
    'total_knowledge_articles': len(knowledge_articles)
}))"}

